// Build <context> block for the LLM and pull short-term memory.
const merge = $('Merge Text').first().json;
const chat_id = String(merge.chat_id);
const user_text = merge.user_text;

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const today = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

// --- Profile -------------------------------------------------------------
const profileRows = $('Read Profile').all().map(i => i.json);
const profileRow = profileRows.find(r => String(r.chat_id) === chat_id) || null;
const interval = Number(profileRow?.training_days_interval) || 1;

// --- Today's food sum ----------------------------------------------------
const foodRows = $('Read Food Log').all().map(i => i.json);
const todayFood = foodRows.filter(r => String(r.date) === today);
const todaySum = todayFood.reduce((acc, r) => ({
  kcal:    acc.kcal    + (Number(r.kcal)    || 0),
  protein: acc.protein + (Number(r.protein) || 0),
  fat:     acc.fat     + (Number(r.fat)     || 0),
  carbs:   acc.carbs   + (Number(r.carbs)   || 0),
}), { kcal: 0, protein: 0, fat: 0, carbs: 0 });

// --- Last workout --------------------------------------------------------
const workoutRows = $('Read Workout Log').all().map(i => i.json);
const sortedW = workoutRows
  .filter(r => r.date)
  .sort((a, b) => String(a.date).localeCompare(String(b.date)));
const lastWorkout = sortedW[sortedW.length - 1] || null;

function parseWorkoutNumber(plan) {
  if (!plan) return null;
  const m = String(plan).match(/№?\s*([1-4])/);
  if (m) return Number(m[1]);
  const s = String(plan).toLowerCase();
  if (s.includes('грудь') && s.includes('бицепс')) return 1;
  if (s.includes('плечи') && s.includes('грудь'))  return 2;
  if (s.includes('спина') && s.includes('трицепс'))return 3;
  if (s.includes('ноги')) return 4;
  return null;
}

let expected_today;
if (!lastWorkout) {
  expected_today = { type: 'workout', number: 1, label: '№1' };
} else {
  const lastDate = new Date(String(lastWorkout.date));
  const todayD   = new Date(today);
  const daysSince = Math.floor((todayD - lastDate) / (1000*60*60*24));
  if (daysSince < interval) {
    expected_today = { type: 'rest', days_until_next: interval - daysSince };
  } else {
    const lastN = parseWorkoutNumber(lastWorkout.day_plan) || 0;
    const nextN = (lastN % 4) + 1;
    expected_today = { type: 'workout', number: nextN, label: `№${nextN}` };
  }
}

// --- Workouts catalog (читается из листа workouts_flat) -----------------
const wkRows = $('Read Workouts Catalog').all().map(i => i.json);
const blocks = { 1: [], 2: [], 3: [], 4: [] };
for (const r of wkRows) {
  const n = Number(r.block_num);
  if (!n || !blocks[n]) continue;
  if (!r.exercise) continue;
  blocks[n].push({
    group:    r.group    || '',
    exercise: r.exercise || '',
    sets:     r.sets     != null ? String(r.sets)   : '',
    reps:     r.reps     != null ? String(r.reps)   : '',
    weight:   r.weight   != null ? String(r.weight) : '',
    note:     r.note     || '',
  });
}
const BLOCK_LABELS = {
  1: '№1 Грудь + Бицепс',
  2: '№2 Плечи + Грудь',
  3: '№3 Спина + Трицепс',
  4: '№4 Ноги',
};

// --- Short-term memory (per chat_id, persists in workflow staticData) ----
const sd = $getWorkflowStaticData('global');
sd.chats = sd.chats || {};
sd.chats[chat_id] = sd.chats[chat_id] || { recent: [], last_intent: null, last_intent_date: null };
const mem = sd.chats[chat_id];
// Если последний intent был не сегодня — сбрасываем, не тащим вчерашнее в контекст.
if (mem.last_intent_date && mem.last_intent_date !== today) {
  mem.last_intent = null;
  mem.last_intent_date = null;
}
const recentDialog = (mem.recent || []).slice(-6);

// --- Compose <context> ---------------------------------------------------
const lines = [];
lines.push('<context>');
if (profileRow) {
  lines.push(`Профиль: рост=${profileRow.height_cm}см, вес=${profileRow.weight_kg}кг, возраст=${profileRow.age}, пол=${profileRow.sex}, цель=${profileRow.goal || 'не задана'}.`);
  const bmr = Number(profileRow.bmr) || 1600;
  const baseline = Number(profileRow.daily_baseline_kcal) || 280;
  const goal = String(profileRow.goal || 'maintain').toLowerCase();
  const goalMult = ({ lose: 0.8, maintain: 1.0, gain: 1.15 })[goal] || 1.0;

  // --- Реальный расход за сегодня (динамически) ----------------------
  // Ходьба за сегодня:
  const walkRows = $('Read Walking Log').all().map(i => i.json).filter(r => String(r.date) === today);
  const walkKcalToday = walkRows.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);
  const walkMinToday  = walkRows.reduce((s, r) => s + (Number(r.duration_min) || 0), 0);

  // Тренировки за сегодня:
  const todayWorkouts = workoutRows.filter(r => String(r.date) === today);
  const workoutKcalActual = todayWorkouts.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);

  // Если сегодня день тренировки и факт ещё не залогирован — берём ПЛАНОВУЮ оценку
  // расхода тренировки (MET × вес × default_min). После log_workout заменится на факт.
  let workoutKcalPlanned = 0;
  if (expected_today.type === 'workout') {
    const blockNum = expected_today.number;
    const weight = Number(profileRow.weight_kg) || 76;
    const planExercises = blocks[blockNum] || [];
    // Пересчитаем по met/default_min из workouts_flat (вернёмся к raw rows из Read Workouts Catalog).
    const wkRows2 = $('Read Workouts Catalog').all().map(i => i.json);
    for (const r of wkRows2) {
      if (Number(r.block_num) !== blockNum) continue;
      if (!r.exercise) continue;
      const met = Number(r.met) || 0;
      const dm  = Number(r.default_min) || 0;
      if (met && dm) workoutKcalPlanned += met * weight * dm / 60;
    }
  }
  const workoutKcalToday = todayWorkouts.length > 0 ? workoutKcalActual : Math.round(workoutKcalPlanned);
  const workoutSourceLabel = todayWorkouts.length > 0 ? 'факт' : (workoutKcalPlanned > 0 ? 'план' : 'нет');

  const tdeeToday = bmr + baseline + walkKcalToday + workoutKcalToday;
  const targetKcalToday = Math.round(tdeeToday * goalMult);

  // Минимум — не уходить ниже BMR × 1.1; максимум — не выше базового × 1.4
  const targetFloor = Math.round(bmr * 1.1);
  const targetCap   = Math.round((bmr + baseline) * goalMult * 1.4);
  const targetKcalTodayClamped = Math.max(targetFloor, Math.min(targetCap, targetKcalToday));

  lines.push(`📊 Расчёт расхода на сегодня:`);
  lines.push(`- BMR: ${bmr} ккал`);
  lines.push(`- Повседневная активность (фон): ${baseline} ккал`);
  if (walkRows.length) {
    lines.push(`- Ходьба сегодня всего: ${walkMinToday} мин, ${walkKcalToday} ккал. Сессии:`);
    for (const r of walkRows) {
      const act = r.activity || 'walking';
      const sp  = r.speed_kmh ? `${r.speed_kmh} км/ч` : '?';
      const dist = r.distance_km ? `${r.distance_km}км ` : '';
      lines.push(`  · ${r.time || ''} ${act}: ${r.duration_min}мин ${dist}@ ${sp} → ${r.kcal_burned} ккал`);
    }
  } else {
    lines.push(`- Ходьба сегодня: ещё не залогирована`);
  }
  if (todayWorkouts.length) {
    lines.push(`- Тренировка сегодня (факт): ${workoutKcalToday} ккал`);
  } else if (workoutKcalPlanned > 0) {
    lines.push(`- Тренировка сегодня (план, ${expected_today.label}): ~${workoutKcalToday} ккал — учтено в бюджете, заменится на факт после log_workout`);
  } else {
    lines.push(`- Тренировка сегодня: ещё не было/не залогирована`);
  }
  lines.push(`- Итого расход: ${tdeeToday} ккал`);
  if (targetKcalTodayClamped !== targetKcalToday) {
    if (targetKcalTodayClamped < targetKcalToday) {
      lines.push(`Сырой расчёт цели: ${targetKcalToday} ккал. ⚠️ Сработал ПОТОЛОК (cap = базовая цель × 1.4 = ${targetCap} ккал). Это страховка — если за день много активности, бюджет всё равно не растёт выше ${targetCap}, чтобы не съесть лишнего «под расход».`);
      lines.push(`Цель на сегодня (с учётом cap): ${targetKcalTodayClamped} ккал.`);
    } else {
      lines.push(`Сырой расчёт цели: ${targetKcalToday} ккал. ⚠️ Сработал ПОЛ (floor = BMR × 1.1 = ${targetFloor} ккал). Это защита — нельзя уходить ниже, иначе слишком жёсткий дефицит.`);
      lines.push(`Цель на сегодня (с учётом floor): ${targetKcalTodayClamped} ккал.`);
    }
  } else {
    lines.push(`Цель (${goal} × ${goalMult}): ${targetKcalTodayClamped} ккал.`);
  }
  lines.push(`Белок: ${profileRow.target_protein_g}г, жиры: ${profileRow.target_fat_g}г, углеводы: ${profileRow.target_carbs_g}г.`);
  lines.push(`Интервал тренировок: ${interval} дн. Тип дня по циклу: ${expected_today.type === 'workout' ? 'тренировка №' + expected_today.number : 'отдых'}.`);
  profileRow.__target_kcal_today = targetKcalTodayClamped;
} else {
  lines.push('Профиль НЕ заполнен. Если пользователь даёт антропометрию (рост/вес/возраст/пол/активность/цель) — используй action=set_profile. Если он сразу называет ккал-цель — action=set_goals.');
}
lines.push(`Сегодня (${today}) съедено: ${todaySum.kcal} ккал, Б=${todaySum.protein}г, Ж=${todaySum.fat}г, У=${todaySum.carbs}г.`);
if (todayFood.length) {
  lines.push('Записи food_log за сегодня (используй для daily_summary разбивкой):');
  for (const r of todayFood) {
    const t = r.time ? `${r.time} ` : '';
    const desc = r.description || '(без описания)';
    const kcal = r.kcal != null ? r.kcal : '?';
    const p = r.protein != null ? r.protein : '?';
    const f = r.fat != null ? r.fat : '?';
    const c = r.carbs != null ? r.carbs : '?';
    lines.push(`- ${t}${desc} — ${kcal} ккал (Б${p}/Ж${f}/У${c})`);
  }
}
if (profileRow?.target_kcal) {
  const targetToday = profileRow.__target_kcal_today || Number(profileRow.target_kcal);
  const left = targetToday - todaySum.kcal;
  lines.push(`Остаток до цели на сегодня: ${left} ккал (${todaySum.kcal} съедено из ${targetToday}).`);
}
if (profileRow?.target_protein_g) {
  const targetP = Number(profileRow.target_protein_g);
  const leftP = targetP - todaySum.protein;
  lines.push(`Белок: ${todaySum.protein}г съедено из ${targetP}г. Осталось добрать: ${leftP}г.`);
}
if (profileRow?.target_fat_g) {
  const targetF = Number(profileRow.target_fat_g);
  lines.push(`Жиры: ${todaySum.fat}г из ${targetF}г.`);
}
if (profileRow?.target_carbs_g) {
  const targetC = Number(profileRow.target_carbs_g);
  lines.push(`Углеводы: ${todaySum.carbs}г из ${targetC}г.`);
}
if (lastWorkout) {
  lines.push(`Последняя тренировка: ${lastWorkout.date} — ${lastWorkout.day_plan}.`);
} else {
  lines.push('Тренировок ещё не было.');
}
if (expected_today.type === 'rest') {
  lines.push(`Сегодня по циклу — ОТДЫХ. Следующая тренировка через ${expected_today.days_until_next} дн.`);
} else {
  lines.push(`Сегодня по циклу — Трен ${expected_today.label}.`);
  const ex = blocks[expected_today.number] || [];
  if (ex.length) {
    lines.push(`Упражнения для ${expected_today.label}:`);
    for (const e of ex) {
      const w = e.weight && e.weight !== '—' ? `, ${e.weight}` : '';
      const note = e.note ? ` (${e.note})` : '';
      lines.push(`- ${e.group}: ${e.exercise}, ${e.sets}×${e.reps}${w}${note}`);
    }
  }
}

// Полный план всех 4 блоков — для вопросов "в какой день добавить упражнение",
// "что в №3", "замени Y на Z" и т.п.
const hasAnyBlock = [1,2,3,4].some(n => blocks[n].length > 0);
if (hasAnyBlock) {
  lines.push('');
  lines.push('Полный план тренировок (все 4 блока):');
  for (const n of [1, 2, 3, 4]) {
    if (!blocks[n].length) continue;
    lines.push(`-- ${BLOCK_LABELS[n]} --`);
    for (const e of blocks[n]) {
      const w = e.weight && e.weight !== '—' ? `, ${e.weight}` : '';
      const note = e.note ? ` (${e.note})` : '';
      lines.push(`  ${e.group}: ${e.exercise}, ${e.sets}×${e.reps}${w}${note}`);
    }
  }
}
// --- Products catalog -------------------------------------------
const productsRows = $('Read Products').all().map(i => i.json).filter(r => r && r.name);
if (productsRows.length) {
  lines.push('');
  lines.push('Справочник продуктов (используй ТОЧНЫЕ числа отсюда, не угадывай):');
  for (const p of productsRows) {
    const aliases = p.aliases ? ` [${p.aliases}]` : '';
    const ds = p.default_serving_g ? `, 1 порция = ${p.default_serving_g}г` : '';
    const notes = p.notes ? ` — ${p.notes}` : '';
    lines.push(`- ${p.name}${aliases}: ${p.kcal_per_100g} ккал / Б${p.protein_per_100g} / Ж${p.fat_per_100g} / У${p.carbs_per_100g} на 100г${ds}${notes}`);
  }
}
if (mem.last_intent) {
  lines.push(`Контекст диалога: пользователь сегодня уже упомянул план «${mem.last_intent}».`);
}
if (recentDialog.length) {
  lines.push('Недавние реплики:');
  for (const t of recentDialog) lines.push(`  ${t.role}: ${t.text}`);
}

// ━━━ Анти-loop для уточнений ━━━
// Если предыдущий ответ бота был ask_clarify — текущее сообщение это ОТВЕТ.
// Подаём это очень громко в самом конце, чтобы модель точно увидела.
if (mem.pending_clarify) {
  const pc = mem.pending_clarify;
  lines.push('');
  lines.push('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  lines.push('⚠️ КРИТИЧНО: текущее сообщение пользователя — это ОТВЕТ на твой уточняющий вопрос.');
  lines.push(`Прошлое сообщение USER: "${pc.original_user_msg}"`);
  lines.push(`Твой вопрос (ask_clarify): "${pc.bot_question}"`);
  if (pc.pending_items && pc.pending_items.length) {
    lines.push(`Ждали уточнения по: ${pc.pending_items.join(', ')}`);
  }
  lines.push(`Текущее USER (это ОТВЕТ на твой вопрос): "${user_text}"`);
  lines.push('');
  lines.push('ИНСТРУКЦИЯ:');
  lines.push('1. Склей описание из «Прошлое сообщение USER» с цифрами/уточнениями из «Текущее USER».');
  lines.push('2. Верни action=log_food (или log_workout/log_walking — что соответствует контексту), НЕ повторяй ask_clarify.');
  lines.push('3. Если ответ юзера типа «X грамм всего», «вместе X грамм», «на всё X», «итого X» — это ОБЩАЯ масса для всех упомянутых ранее блюд. Раздели поровну или по логичной пропорции (например грибы:баклажан = 60:40).');
  lines.push('4. Если ответ односложный или очень короткий («50 грамм», «20 минут») — это и есть числа для долога. Не переспрашивай.');
  lines.push('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
}
lines.push('</context>');
const context = lines.join('\n');

return [{ json: { chat_id: merge.chat_id, user_text, context, expected_today } }];

const raw = $input.first().json;
let text =
  raw?.output?.[0]?.content?.[0]?.text ??
  raw?.message?.content ??
  raw?.choices?.[0]?.message?.content ??
  raw?.content ??
  raw?.text ??
  raw;
if (typeof text !== 'string') text = JSON.stringify(text);
text = text.trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

// Модель иногда вставляет // комментарии — стандартный JSON.parse на них падает.
text = text.replace(/\/\/[^\n\r]*/g, '');
// И блочные комментарии /* ... */ на всякий.
text = text.replace(/\/\*[\s\S]*?\*\//g, '');
// Trailing запятые перед } или ] (строгий JSON их не разрешает).
text = text.replace(/,(\s*[}\]])/g, '$1');

// Модель иногда отдаёт числа выражениями: "kcal": 690 + 570 + 50.
// Заменяем такие выражения на готовое число до JSON.parse.
text = text.replace(/(:\s*)([\d.]+(?:\s*[+\-*]\s*[\d.]+)+)(\s*[,}\]])/g, (m, pre, expr, post) => {
  if (!/^[\d\s+\-*.]+$/.test(expr)) return m;
  try {
    const v = Function(`"use strict"; return (${expr})`)();
    if (typeof v === 'number' && Number.isFinite(v)) return `${pre}${v}${post}`;
  } catch (e) {}
  return m;
});

let payload;
try { payload = JSON.parse(text); }
catch (e) { payload = { action: 'chat', data: {}, reply: text }; }
if (!payload || typeof payload !== 'object') payload = { action: 'chat', data: {}, reply: String(payload) };

// Нормализуем action: модель порой пишет logfood вместо log_food.
const ACTION_MAP = {
  logfood: 'log_food', logworkout: 'log_workout', logbody: 'log_body',
  setprofile: 'set_profile', setgoals: 'set_goals', planworkout: 'plan_workout',
  dailysummary: 'daily_summary', showworkout: 'show_workout',
  askclarify: 'ask_clarify', deletefood: 'delete_food',
  forecastfood: 'forecast_food', logwalking: 'log_walking', addproduct: 'add_product', chat: 'chat',
};
if (typeof payload.action === 'string') {
  const norm = payload.action.toLowerCase().replace(/[^a-z]/g, '');
  payload.action = ACTION_MAP[norm] || payload.action;
}
if (!payload.action) payload.action = 'chat';

// Нормализуем ключи в data: mealtype → meal_type, kcalburned → kcal_burned, ...
const DATA_KEY_MAP = {
  mealtype: 'meal_type', kcalburned: 'kcal_burned', durationmin: 'duration_min',
  dayplan: 'day_plan', exercisesdone: 'exercises_done',
  bodyfatpct: 'body_fat_pct', heightcm: 'height_cm', weightkg: 'weight_kg',
  activitylevel: 'activity_level', trainingdaysinterval: 'training_days_interval',
  targetkcal: 'target_kcal', pendingitems: 'pending_items',
};
if (payload.data && typeof payload.data === 'object' && !Array.isArray(payload.data)) {
  const fixed = {};
  for (const [k, v] of Object.entries(payload.data)) {
    const norm = k.toLowerCase().replace(/[^a-z]/g, '');
    fixed[DATA_KEY_MAP[norm] || k] = v;
  }
  payload.data = fixed;
} else {
  payload.data = {};
}
if (!payload.reply) payload.reply = '...';

// Детерминистский пересчёт kcal_burned для log_walking.
// Модель часто промахивается с MET, считаем сами по таблице.
if (payload.action === 'log_walking' && payload.data && typeof payload.data === 'object') {
  const minutes = Number(payload.data.duration_min) || 0;
  let speed = Number(payload.data.speed_kmh);
  const distance = Number(payload.data.distance_km);
  // Если скорости нет, но есть дистанция и время — посчитаем
  if (!speed && distance && minutes) speed = distance / (minutes / 60);
  if (!speed) speed = 3.5; // дефолт ходьбы

  // MET по скорости (по тексту промпта)
  let met;
  if (speed < 4)        met = 2.8;
  else if (speed < 5.5) met = 3.5;
  else if (speed < 6.5) met = 4.3;
  else if (speed < 8.5) met = 6;
  else                  met = 8;
  // Хайкинг/походы могут идти отдельно; если activity=hiking — поднимем met.
  const activity = String(payload.data.activity || '').toLowerCase();
  if (activity.includes('hik') || activity.includes('поход') || activity.includes('лес') || activity.includes('гор')) met = Math.max(met, 6);

  // Вес берём из профиля.
  const profRows = $('Read Profile').all().map(i => i.json);
  const prof = profRows.find(r => String(r.chat_id) === String(payload.chat_id || $('Build Context').first().json.chat_id)) || profRows[0];
  const weight = Number(prof?.weight_kg) || 76;

  if (minutes > 0) {
    const kcalCalc = Math.round(met * weight * minutes / 60);
    payload.data.kcal_burned = kcalCalc;
    payload.data.speed_kmh = speed;
    payload.data.met_used = met;
    // Если в reply было неправильное число — заменим на пересчитанное.
    if (typeof payload.reply === 'string') {
      // Заменяем все «ХХХ ккал» рядом со «сжёг» на правильное.
      payload.reply = payload.reply.replace(/(сжёг|сжег|сожгли|сожжено)\s*[~≈]?\s*\d+\s*ккал/gi, `$1 ${kcalCalc} ккал`);
    }
  }
}

// Детерминистский фикс вердикта для forecast_food.
// Модель часто корректно считает математику, но проставляет неправильный значок
// (например ставит ❌ НЕ ВЛЕЗАЕТ при положительном остатке). Чиним.
if (payload.action === 'forecast_food' && typeof payload.reply === 'string') {
  const m = payload.reply.match(/остаток[^:]{0,40}будет[:\s]*(-?\d+(?:[.,]\d+)?)/i)
         || payload.reply.match(/после[^\d-]{0,30}(-?\d+(?:[.,]\d+)?)\s*ккал/i);
  if (m) {
    const remaining = parseFloat(String(m[1]).replace(',', '.'));
    let correctVerdict;
    if (remaining < 0)        correctVerdict = '❌ НЕ ВЛЕЗАЕТ';
    else if (remaining < 200) correctVerdict = '⚠️ ВПРИТЫК';
    else                       correctVerdict = '✅ ВЛЕЗАЕТ В БЮДЖЕТ';
    payload.reply = payload.reply.replace(/(❌\s*НЕ\s*ВЛЕЗАЕТ|⚠️\s*ВПРИТЫК|✅\s*ВЛЕЗАЕТ(?:\s*С\s*ЗАПАСОМ)?(?:\s*В\s*БЮДЖЕТ)?)/gi, correctVerdict);
  }
}

const bc = $('Build Context').first().json;
const chat_id = bc.chat_id;
const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const date = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const time = `${pad(now.getHours())}:${pad(now.getMinutes())}`;

return [{ json: { ...payload, chat_id, date, time } }];

const item = $input.first().json;
const chat_id = String(item.chat_id);
const userText = $('Merge Text').first().json.user_text;
const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const today = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

const sd = $getWorkflowStaticData('global');
sd.chats = sd.chats || {};
sd.chats[chat_id] = sd.chats[chat_id] || { recent: [], last_intent: null, last_intent_date: null, pending_clarify: null };
const mem = sd.chats[chat_id];

mem.recent = mem.recent || [];
mem.recent.push({ role: 'user', text: userText });
mem.recent.push({ role: 'bot',  text: item.reply, action: item.action });
if (mem.recent.length > 12) mem.recent = mem.recent.slice(-12);

mem.last_bot_action = item.action;

// Если бот вернул ask_clarify — запомним детали, чтобы на следующем ходе склеить контекст.
if (item.action === 'ask_clarify') {
  mem.pending_clarify = {
    original_user_msg: userText,
    bot_question: item.reply,
    pending_items: (item.data && item.data.pending_items) || [],
    set_at: today,
  };
} else {
  // На любое не-ask_clarify действие очищаем pending — уточнение разрешилось.
  mem.pending_clarify = null;
}

if (item.action === 'plan_workout' && item.data?.day_plan) {
  mem.last_intent = item.data.day_plan;
  mem.last_intent_date = today;
} else if (item.action === 'log_workout') {
  mem.last_intent = null;
  mem.last_intent_date = null;
}

// === Дневной счётчик токенов с предупреждением ===
// Лимит free tier на gpt-4o (и full models): 250k токенов/день.
const DAILY_LIMIT = 250000;
const SOFT = 200000; // 80%
const HARD = 240000; // 96%

sd.usage = sd.usage || { date: today, total: 0, warned_soft: false, warned_hard: false };
if (sd.usage.date !== today) {
  sd.usage = { date: today, total: 0, warned_soft: false, warned_hard: false };
}

// Смотрим usage из последнего вызова модели (langchain openAi v2.3 кладёт в .usage).
const llmRaw = $('Message a model').first().json;
const used = Number(
  llmRaw?.usage?.total_tokens ??
  llmRaw?.usage?.input_tokens + llmRaw?.usage?.output_tokens ??
  0
);
sd.usage.total += isNaN(used) ? 0 : used;

let warning = null;
if (sd.usage.total >= HARD && !sd.usage.warned_hard) {
  sd.usage.warned_hard = true;
  warning = `🚨 Лимит токенов почти достигнут: ${sd.usage.total.toLocaleString('ru')} из ${DAILY_LIMIT.toLocaleString('ru')} (~${Math.round(100*sd.usage.total/DAILY_LIMIT)}%). Дальнейшие запросы могут пойти в платный режим. Постарайся писать важное только до конца дня.`;
} else if (sd.usage.total >= SOFT && !sd.usage.warned_soft) {
  sd.usage.warned_soft = true;
  warning = `⚠️ Использовано ${sd.usage.total.toLocaleString('ru')} токенов из дневных ${DAILY_LIMIT.toLocaleString('ru')} (~${Math.round(100*sd.usage.total/DAILY_LIMIT)}%). До платного режима осталось ~${(DAILY_LIMIT - sd.usage.total).toLocaleString('ru')} токенов.`;
}

if (warning) {
  item.reply = `${item.reply}\n\n———\n${warning}`;
}

return [{ json: item }];

const item = $input.first().json;
const d = item.data || {};
const sex = (() => {
  const s = String(d.sex || 'm').toLowerCase();
  if (s.startsWith('f') || s.startsWith('ж')) return 'f';
  return 'm';
})();
const height = Number(d.height_cm) || 0;
const weight = Number(d.weight_kg) || 0;
const age    = Number(d.age) || 0;
const activity = String(d.activity_level || 'moderate').toLowerCase();
const goal     = String(d.goal || 'maintain').toLowerCase();
const actMult = ({ sedentary:1.2, light:1.375, moderate:1.55, active:1.725, very:1.9 })[activity] || 1.55;
const goalMult = ({ lose:0.8, maintain:1.0, gain:1.15 })[goal] || 1.0;
const bmr_raw = sex === 'f'
  ? 10*weight + 6.25*height - 5*age - 161
  : 10*weight + 6.25*height - 5*age + 5;
const bmr = Math.round(bmr_raw);
const tdee = bmr_raw * actMult;
const target_kcal      = Math.round(tdee * goalMult);
const target_protein_g = Math.round(weight * 1.8);
const target_fat_g     = Math.round(weight * 1.0);
const target_carbs_g   = Math.max(0, Math.round((target_kcal - target_protein_g*4 - target_fat_g*9) / 4));
const training_days_interval = Number(d.training_days_interval) || 1;
const daily_baseline_kcal = Number(d.daily_baseline_kcal) || 280;
const updated_at = new Date().toISOString();

return [{ json: {
  ...item,
  profile_row: {
    chat_id: item.chat_id,
    height_cm: height,
    weight_kg: weight,
    age,
    sex,
    activity_level: activity,
    goal,
    training_days_interval,
    bmr,
    daily_baseline_kcal,
    target_kcal,
    target_protein_g,
    target_fat_g,
    target_carbs_g,
    updated_at,
  }
} }];

const item = $input.first().json;
const data = item.data || {};
const criteria = String(data.criteria || 'last_today').toLowerCase();
const query = String(data.query || '').toLowerCase();
const targetDate = String(data.target_date || item.date);

// Items из Read Food Log в том же порядке, что строки в Sheets.
// Header в строке 1 → первая дата-строка = sheet row 2 → item index 0.
const foodRows = $('Read Food Log').all().map((it, idx) => ({
  ...it.json,
  _row: idx + 2,
}));

let target = null;
if (criteria === 'last') {
  target = foodRows[foodRows.length - 1] || null;
} else if (criteria === 'by_description') {
  const matches = foodRows.filter(r =>
    String(r.date) === targetDate &&
    String(r.description || '').toLowerCase().includes(query)
  );
  target = matches[matches.length - 1] || null;
} else { // last_today (default)
  const matches = foodRows.filter(r => String(r.date) === targetDate);
  target = matches[matches.length - 1] || null;
}

if (!target) {
  // Ничего не нашли — на следующую ноду не передаём, чтобы Sheets-удаление не сработало.
  return [];
}

return [{ json: {
  ...item,
  _row: target._row,
  deleted_description: target.description,
  deleted_kcal: target.kcal,
} }];
